UPDATE course_contents
SET week_plan = $week_data$[{"week":2,"theme":"成为实验建筑师","days_range":"8-14","goals":["学习科学实验设计的核心原则——变量控制、随机化、盲法与数据记录。基于上周提出的研究问题，设计出一套完整的、可以在自己家庭环境中执行的原创实验方案。"],"activities":[{"sequence":8,"day_label":"Day 8-9","day_range":"8-9","title_zh":"科学方法论入门（上）：控制你的“变量”","title_en":"Scientific Methodology 101 (Part 1","duration":"约60分钟，可在2天内完成","content":": Controlling Your Variables)\n(任务时长：约60分钟，可在2天内完成)\n青年研究员，上周我们提出了一个绝妙的核心问题。但这就像有了一张藏宝图，我们还需要建造一艘坚固的船才能出海寻宝。这艘船，就是我们的**“实验设计方案”**。\n建造这艘船的第一块龙骨，叫做**“变量控制”**。\n在科学实验中，“变量”指的是那些可能会改变的东西。为了让我们的实验可信，我们必须像侦探一样，把所有可能影响结果的“嫌疑变量”都控制住，只留下我们真正想研究的那一个。\n自变量 (Independent Variable): 这是我们主动改变的东西，是我们想测试其效果的“原因”。在我们的实验中，自变量就是**“主人的状态”**（是决定回家了，还是没决定）。\n因变量 (Dependent Variable): 这是我们观察和测量的东西，是我们想看的“结果”。在我们的实验中，因变量就是**“宠物的行为”**（是否表现出等待）。\n控制变量 (Controlled Variables): 这是所有其他可能影响“结果”的因素，我们必须努力让它们保持不变。这些就是我们上周讨论过的各种“干扰”！\n思考挑战：\n回想一下谢尔德雷克博士的实验，他都控制了哪些变量？\n他让主人随机时间回家，是为了控制【习惯/时间】这个变量。\n他让主人坐出租车，是为了控制【熟悉的声音】这个变量。\n他让家人不知道回家时间，是为了控制【家中他人的暗示】这个变量。\n理解自变量、因变量和控制变量的概念。\n头脑风暴： 在你的家庭环境中，除了上面提到的几点，还有哪些独特的“控制变量”需要我们注意？（例如：家里是不是有固定的喂食时间？窗外是不是有邻居的狗会定时吠叫？这些都可能影响你宠物的行为。）\n提交你的“变量控制清单”：\n在下方的文本框中，列出你认为在你的实验中需要控制的所有变量。清单越详细，你的“船”就越坚固！\n格式：\n自变量： 主人的决定（回家 vs. 不回家）。\n因变量： 宠物的等待行为。\n我的控制变量清单：\n时间： 必须是随机的，不能有规律。\n声音： 不能有熟悉的汽车或脚步声。\n家中他人： 留守在家的人不能知道实验计划。\n固定事件： 实验时间要避开家里固定的喂食时间或散步时间。\n（请你继续列出至少2条你家特有的需要控制的变量）……"},{"sequence":10,"day_label":"Day 10-12","day_range":"10-12","title_zh":"科学方法论入门（下）：随机、双盲与量子骰子","title_en":"Scientific Methodology 101 (Part 2","duration":"约75分钟，可在3天内完成","content":": Randomization, Double-Blind & The Quantum Die)\n(任务时长：约75分钟，可在3天内完成)\n青年研究员，我们已经学会了如何控制那些看得见的“变量”。但科学中最强大的敌人，是我们自己——我们大脑的期望和偏见。为了战胜这个敌人，科学家发明了两件强大的“隐形盔甲”：随机化 和 盲法。\n想象一位魔法师发明了一种“快乐药水”。他找来10个志愿者测试。他给其中5个他认为会喜欢药水的人喝了药水，给另外5个他觉得比较挑剔的人喝了白水。结果，喝了药水的人都说感觉很快乐！\n这个实验可靠吗？\n不可靠！因为魔法师的期望已经影响了实验。他可能对喝药水的人更热情，对喝白水的人很冷淡，这种态度本身就可能让人感到快乐或不快乐。\n如何改进？\n随机化 (Randomization): 用抛硬币的方式决定谁喝药水，谁喝白水。这样就消除了魔法师的主观选择偏见。\n盲法 (Blind):\n单盲 (Single-Blind): 不告诉志愿者他们喝的是什么。这样志愿者的期望就不会影响结果。\n双盲 (Double-Blind): 魔法师自己也不知道哪瓶是药水，哪瓶是白水（让他的助手贴上A、B标签）。只有在实验结束后，助手才公布答案。这样，魔法师在互动时的无意识偏见也被消除了。\n现在，回到我们的实验：\n随机化： 我们如何决定主人是“立刻回家”还是“再待一小时”？必须是完全随机的！我们可以用抛硬币，或者，为了更酷一点，我们可以使用量子随机数生成器。量子世界的随机性是物理学定律保证的“真随机”，这能让我们的实验无懈可击。\n盲法： 在我们的实验中，宠物已经是“盲”的了。关键是，分析数据的人（也就是你！）在分析视频的时候，一开始最好也不知道每个时间段对应的是“主人已决定回家”还是“未决定”。这可以防止你因为期望而“过度解读”宠物的行为。（我们将在数据分析阶段实现这一点）\n理解随机化和双盲的必要性。\n思考：为什么“真随机”对于区分“心灵感应”和“巧合”如此重要？\n探索量子骰子： 盖亚为你准备了一个小工具——一个真实的量子随机数生成器。它通过测量量子的不确定性来产生数字。点击下面的按钮来体验一下，看看它生成的“0”和“1”序列是不是毫无规律可循。\n提交你的“双盲思考”：\n在下方的文本框中，回答以下问题：\n问题： 在我们的实验里，如果不由盖亚来自动分析视频，而是由你自己亲自观看录像来判断宠物“是否在等待”，你认为“双盲”有多重要？请描述一个**你可能会无意中犯下的“偏见错误”**的例子。\n示例回答： “双盲非常重要。因为如果我知道下午3:00-3:10是‘主人已决定回家’的时间段，当我在看这段录像时，我可能会把我的狗狗一次很普通的伸懒腰、抬头，也解读为‘它有反应了！’。但如果我不知道，我可能就会认为那只是一次普通的伸懒腰。”"},{"sequence":13,"day_label":"Day 13-14","day_range":"13-14","title_zh":"撰写你的实验方案","title_en":"Writing Your Experimental Protocol","duration":"约60分钟，可在2天内完成","content":"(任务时长：约60分钟，可在2天内完成)\n青年研究员，现在你已经掌握了所有的理论工具，是时候把它们组合起来，绘制出我们“杰提计划”的最终蓝图——一份完整的、可执行的实验方案了。\n这份方案将是你未来几周行动的唯一指南。它必须像一份食谱或一份建筑图纸一样，清晰、准确、无可挑剔。\n请你在你的数字日记或纸质日记中，完整地写下你的实验方案。它应该包含以下部分：\n研究问题： (从上周的作业中复制过来)\n实验假设 (Hypothesis): (你预测的结果是什么？)\n例如：我假设，宠物开始等待的时间与主人‘做出回家决定’的时刻显著相关。\n实验材料 (Materials):\n例如：一台可以录像的手机或摄像头、一个三脚架、宠物的等待区域（如门口的垫子）、一个可以上网并使用盖亚App的手机（供离家的主人使用）、我的《第六感日记》本。\n实验步骤 (Procedure): (这是最重要的部分，请尽可能详细！)\n准备阶段： 离家的主人(A)和留守的观察员(B)约定好大致的实验时间窗口（例如下午3-5点）。B在家中架设好摄像头，确保能清晰拍到宠物的“等待区域”。\n出发： A正常离家，到达一个离家至少5公里以外的地点（例如办公室、咖啡馆），我们称之为“决定点A”。\n触发随机化： 在实验时间窗口内，A打开盖亚App，点击“开始实验”。App将启动一个量子随机数生成器，生成结果“1”（立刻回家）或“0”（延迟回家）。\n记录决定时刻： 在生成结果的瞬间，A在App上点击“我已决定”，盖亚将记录下这个精确的时间点，我们称之为 T1 (Time of Decision)。\n执行随机指令：\n如果结果是**“1”**：A立刻动身回家。在A走出大门或发动汽车的瞬间，再次点击App上的“我已出发”，盖亚记录下这个时间点 T2 (Time of Movement)。\n如果结果是**“0”**：A必须在“决定点A”继续停留一个固定的、较长的时间（例如：1小时），期间可以做任何与回家无关的事情。1小时后，再动身回家。\n家中记录： 在整个过程中，家中的摄像头不间断录像。\n实验结束： A回到家中，本次实验数据记录完毕。\n数据记录与分析方法 (Data Recording & Analysis):\n我将把每一天的录像上传给盖亚，并标记出T1和T2的时间点。盖亚将自动分析在T1前后10分钟内，以及T2前后10分钟内，我的宠物在‘等待区域’停留的总时长百分比，并生成对比图表。\n逐字逐句地检查你写的实验方案，想象你是一个完全不了解这个实验的人，你能只看这份方案就准确无误地执行吗？\n提交你的完整实验方案：\n请在下方的文本框中，打字输入你最终版本的、完整的实验方案。请确保包含了上述所有五个部分。\n这份方案将被作为你项目中期审核的重要依据。\n恭喜你，伟大的实验建筑师！你已经成功设计出了一艘坚固、精密、足以抵御偏见风暴的科学之船。从下周开始，我们将正式扬帆起航，进入激动人心的实验执行阶段。准备好迎接真实世界的数据了吗？它可能会给你带来惊喜，也可能会带来挑战，但无论如何，这都将是一段难忘的旅程！"}]},{"week":3,"theme":"扬帆起航——首次数据航行","days_range":"15-21","goals":["将上周设计的实验方案付诸实践。成功完成至少两次完整的实验数据收集，包括视频录制、时间点标记和数据上传。学习如何应对实验过程中可能出现的各种意外状况。"],"activities":[{"sequence":15,"day_label":"Day 15","day_range":"15","title_zh":"出航前检查：设备调试与场地布置","title_en":"Pre-voyage Check: Equipment & Site Setup","duration":"约45分钟","content":"(任务时长：约45分钟)\n青年研究员，我们的“科学之船”——实验方案已经绘制完毕。但在真正出海之前，一位谨慎的船长必须对船上的每一个部件进行最后的检查。今天，我们的任务就是确保所有“设备”都处于最佳状态。\n请逐项检查并确认：\n摄像设备：\n¨ \n找一个手机或摄像头，确保它有足够的电量（最好全程插着电源）和足够的存储空间（至少能录制2-3小时）。\n¨ \n清洁镜头，确保画面清晰。\n拍摄角度与场地：\n¨ \n找到一个最佳的拍摄位置。这个位置需要满足：\n能完整、清晰地拍到你定义的“等待区域”（比如门口的垫子、窗台）。\n不会轻易被宠物撞倒。\n不会妨碍家人正常走动。\n¨ \n用三脚架、书本或其他东西固定好你的摄像设备，确保它在长时间录制中不会移动。\n“等待区域”定义：\n¨ \n明确你实验中的“等待区域”是哪里。是一块特定的地垫？是窗户前一米内的范围？请在你的《第六感日记》中用文字或画图的方式把它精确地定义下来。这对于后续盖亚进行视频分析至关重要。\n离家主人的准备：\n¨ \n确保离家的家人（实验员A）的手机上，能够顺利访问我们的网站和盖亚App。\n¨ \n与家人一起再次熟悉实验流程，特别是如何使用App上的“开始实验”、“我已决定”和“我已出发”按钮。\n进行一次模拟演练。不需要家人真的出门，只需在家中模拟整个流程：架设好设备开始录像 -> 另一位家人在另一个房间打开App点击按钮 -> 检查录像和App记录的时间是否都正常。\n提交你的“准备就绪”证明：\n拍照上传一张你的“实验场地”照片。照片中需要能清晰地看到你架设好的摄像设备以及它所对准的“等待区域”。\n提交你的“等待区域”定义：\n在下方的文本框中，用文字清晰地描述你的“等待区域”。\n格式： “在我的实验中，‘等待区域’被定义为：客厅正门口那块方形的蓝色地垫，以及地垫前方50厘米内的区域。”"}]},{"week":1,"theme":"打破常规——当科学遇到“不可能”","days_range":"1-7","goals":["从“宠物有第六感吗？”的现象层面，深入到“这种‘感应’的本质是什么？”的理论层面。通过案例学习和批判性思维训练，理解常规科学解释的局限性，并正式引入“心灵感应”作为一种需要被严谨检验的科学假说。"],"activities":[{"sequence":1,"day_label":"Day 1-2","day_range":"1-2","title_zh":"案例深度分析：杰提实验的背后","title_en":"Case Deep Dive: Behind the Jaytee Experiments","duration":"约60分钟，可在2天内完成","content":"(任务时长：约60分钟，可在2天内完成)\n你已经不再是“宠物侦探”，而是升级为“青年研究员”了。欢迎来到这个计划，它的名字来源于那只传奇小狗——杰提。在这里，我们将不再满足于“是什么”，而是要勇敢地追问“为什么”和“怎么样”。\n在开始之前，我们需要更深入地了解一下科学家们到底对杰提做了些什么。这不再是一个简单的故事，而是一个真实的科学案例。\n还记得杰提的故事吗？科学家鲁珀特·谢尔德雷克博士为了排除所有已知的可能性，设计了一系列非常巧妙的实验。\n排除【习惯】和【时间感】： 博士让杰提的主人帕姆在完全随机的时间回家。他会给帕姆打电话说：“现在就出发！”这样，杰提就不可能根据“差不多该到时间了”的习惯来等待。\n排除【听觉】： 他让帕姆乘坐完全陌生的出租车回家。这样，就没有了熟悉的引擎声。实验地点离家很远，有时超过20英里，任何声音都不可能传到。\n排除【嗅觉】： 在某些实验中，帕姆会逆风回家，确保她的气味不会被风提前吹到家里。\n排除【家中线索】： 实验的关键是，在帕姆出发前，家里的其他人完全不知道她什么时候会回来。这样，他们就不会因为期待而无意中做出一些小动作（比如开始准备晚餐）来提示杰提。\n实验结果是什么呢？\n在数百次录像实验中，结果惊人地一致：杰提开始在窗边等待的平均时间，是在帕姆接到电话并动身回家后的4分钟左右。而在帕姆没有回家的漫长时间里，杰提几乎很少去窗边。\n下图显示了杰提在窗边时间的统计。蓝色长条代表帕姆在回家路上的10分钟，红色短条代表帕姆出门期间的其他任意10分钟。你可以清楚地看到，杰提绝大多数的等待时间都集中在蓝色时段。\n（前端显示一张简化版的统计图表，X轴是“帕姆不在家时”和“帕姆回家时”，Y轴是“杰提在窗边的时间百分比”，Y轴在“回家时”的部分会非常高。）\n科学界的反应：\n这个实验结果在科学界引起了巨大的争议。很多科学家不相信，他们认为实验中一定还有一些我们没发现的“微妙线索”。但是，谢尔德雷克博士邀请了持怀疑态度的科学家重复他的实验，而他们得到了相似的结果。\n这个谜题，至今悬而未决。它挑战了我们对世界的基本认知。\n仔细阅读背景资料，理解谢尔德雷克博士的每一个实验设计分别是为了排除哪一种常规解释。\n批判性思维挑战： 站在一个“怀疑者”的角度，你还能想到哪些可能的“微妙线索”是博士没有排除掉的吗？（例如：气压的变化？主人手机通话时的某种电磁信号？）\n提交你的“头脑风暴”：\n在下方的文本框中，至少列出两个你认为谢尔德雷克博士的实验可能还存在的“漏洞”或“未排除的干扰因素”。\n格式：\n我的质疑1： 我认为，也许主人在决定回家时，她的手机会发出一种特殊的信号，被家里的某个电器接收到了，然后电器发出了狗狗能听到的超声波。\n我的质疑2： ……"},{"sequence":3,"day_label":"Day 3-5","day_range":"3-5","title_zh":"理论武装：什么是“非定域性”？","title_en":"Theoretical Toolkit: What is 'Non-Locality'?","duration":"约75分钟，可在3天内完成","content":"(任务时长：约75分钟，可在3天内完成)\n青年研究员，你上一个任务提出的质疑非常棒！这正是科学精神的体现。\n现在，我们要进入一个更深、也更奇妙的领域。谢尔德雷克博士和一些物理学家提出了一个大胆的假说：杰提的“感应”可能不是通过任何我们已知的、需要时间在空间中传播的信号（比如声音、光、气味），而是一种**“非定域性”（Non-Locality）**的连接。\n这是个听起来很酷的词，但它到底是什么意思呢？\n想象一下，我（盖亚）给了你和你的好朋友一人一颗非常神奇的骰子。这两颗骰子是一对“双胞胎”，它们被施加了魔法。\n魔法规则是：无论你们相隔多远——你在北京，你的朋友在纽约——只要你们在同一时刻掷出骰子，你们看到的结果永远是相反的。 如果你掷出的是“1”，他掷出的就一定是“6”；如果你掷出“3”，他就一定是“4”。反之亦然。\n重要的是，在你掷出骰子之前，没有任何人——包括你自己和我——知道你会掷出几点。结果是完全随机的。但是，一旦你掷出了“1”，在地球另一端的你朋友的骰子，就在那一瞬间，“知道”了它必须显示为“6”。\n这个信息（“这边是1，你那边必须是6”）的传递，似乎没有花费任何时间，它好像瞬间跨越了整个地球。\n这就是“非定域性”的一个比喻。它描述的是一种超越我们日常理解的、瞬时的、不受空间距离限制的关联。在真实的物理世界里，一些微小的粒子（比如光子）就具有这种“量子纠缠”的特性。\n现在，回到我们的宠物：\n“非定域性”假说认为：主人和宠物之间，可能也存在一种类似“量子纠缠”的宏观连接。当主人在很远的地方做出一个纯粹的“决定”（比如“我要回家了”，这个决定就像你掷出了骰子），这个信息可能会瞬间被宠物“接收”到（就像另一颗骰子瞬间变成了相反的点数），而不需要通过任何需要时间传播的物理信号。\n这个假说，将生物学之谜，与现代物理学最前沿的谜团连接在了一起。\n反复阅读《两颗神奇的骰子》的故事，确保你理解了“非定域性”的核心特征：瞬时性和与距离无关。\n思考：如果宠物与主人的连接是“非定域性”的，那么我们应该观察到什么现象？如果它是通过某种未知的、但仍需时间传播的“经典信号”，我们又会观察到什么不同的现象？\n提交你的理解与推论：\n在下方的文本框中，回答以下两个问题：\n问题A： 请用你自己的话，简单解释一下什么是“非定域性”。\n问题B： 如果主人在月球上“决定”回家，根据“非定域性”假说，地球上的宠物应该在主人做出决定的瞬间就有反应，还是在光信号从月球传到地球的1.3秒后才有反应？请解释你的答案。"},{"sequence":6,"day_label":"Day 6-7","day_range":"6-7","title_zh":"提出你的研究问题","title_en":"Formulating Your Research Question","duration":"约30分钟，可在2天内完成","content":"(任务时长：约30分钟，可在2天内完成)\n青年研究员，我们已经分析了案例，学习了前沿的理论。现在，是时候将这些知识转化为我们自己项目的核心了。\n科学研究的第一步，也是最重要的一步，就是提出一个清晰的、可被检验的研究问题。\n基于我们本周的学习，我们的核心挑战是：如何设计一个实验，来区分两种可能性？\n可能性1（经典信号假说）： 宠物是通过感知主人**开始回家这个【物理行为】**所产生的某种未知信号（这种信号需要时间传播）来做出反应的。\n可能性2（非定域性假说）： 宠物是直接感知到了主人做出回家这个【纯粹意念】，这种感知是瞬时的，与物理行为的开始无关。\n将上述两种可能性，转化为一个清晰的、可以用“是”或“否”来回答的研究问题。一个好的研究问题应该是具体的、可操作的。\n提交你的核心研究问题：\n在下方的文本框中，写下你为我们接下来的项目所确立的核心研究问题。\n没有标准答案，但一个好的例子是：\n“在排除了所有已知感官线索的条件下，家养宠物产生预期主人回家行为的时间点，是与主人‘做出回家决定’的时刻更相关，还是与主人‘开始物理移动’的时刻更相关？”\n非常出色，青年研究员！你已经完成了第一周的理论武装。你不仅理解了问题的复杂性，还掌握了前沿的理论工具，并提出了一个可以引领我们整个项目的核心问题。从下周开始，我们将基于你提出的这个问题，正式开始设计我们自己的原创性实验方案。这将是一次激动人心的智力挑战！准备好了吗？"},{"sequence":16,"day_label":"Day 16-18","day_range":"16-18","title_zh":"第一次试航：完成首次完整实验","title_en":"Maiden Voyage: Completing the First Full Experiment","duration":"实验本身根据你的方案进行，记录和上传约30分钟，可在3天内选择一天完成","content":"(任务时长：实验本身根据你的方案进行，记录和上传约30分钟，可在3天内选择一天完成)\n青年研究员，一切准备就绪。今天，我们将进行第一次完整的实验。请严格按照你上周制定的实验方案执行。\n在与家人（实验员A）约定的时间窗口开始前，架设好摄像设备并开始录制。\n确保家中环境尽可能保持日常状态，不要因为正在实验而表现得过于紧张或不同寻常。正常看书、做作业即可。\n实验过程中，不要主动与宠物互动，让它自然地行动。\n当家人A回家后，停止录制。\n到达“决定点A”后，在约定的时间窗口内，打开盖亚App，点击“开始实验”。\n完全遵从量子随机数生成器的指令（“1”或“0”）。这是保证实验严谨性的核心！\n在App生成结果的瞬间，立刻点击“我已决定”(T1)。\n如果指令是“1”（立刻回家），在你实际迈出第一步或发动汽车的瞬间，立刻点击“我已出发”(T2)。\n正常回家。\n将今天录制的完整视频上传到盖亚的“数据保险库”。\n在你的《第六感日记》中，新开一页，记录本次实验的基本信息。模板如下：\n杰提计划 - 实验记录 第 [ 1 ] 次\n \n实验日期\n \n随机指令\n立刻回家 / 延迟回家 (请圈出)\nT1 (决定时刻)\n（盖亚App会自动记录，你可以在历史记录中查看并抄录）\nT2 (出发时刻)\n（盖亚App会自动记录，你可以在历史记录中查看并抄录）\n实验中的意外情况或特别观察\n（例如：录到一半手机没电了 / 宠物今天好像一直很兴奋 / 楼下邻居在装修，噪音很大）\n确认数据上传：\n在下方的文本框中，输入“第一次实验视频已上传完毕。”\n提交你的实验日志：\n拍照上传你手写的本次《实验记录》页。或者，打字输入表格中的所有内容。"},{"sequence":19,"day_label":"Day 19-21","day_range":"19-21","title_zh":"第二次远航：重复实验与问题解决","title_en":"Second Voyage: Repetition & Troubleshooting","duration":"实验本身根据你的方案进行，记录和上传约30分钟，可在3天内选择一天完成","content":"(任务时长：实验本身根据你的方案进行，记录和上传约30分钟，可在3天内选择一天完成)\n青年研究员，恭喜你完成了第一次实验！但科学研究中，一次的结果可能是巧合。只有能够被重复验证的现象，才具有真正的科学价值。\n因此，本周的最后一个任务，就是再进行一次完整的实验。\n完全重复上一次实验的流程。\n吸取教训： 如果第一次实验中出现了任何意外情况（比如设备问题、环境干扰），请在这次实验前想办法解决或避免。\n手机没电了？ -> 这次全程充电。\n噪音太大了？ -> 尽量选择一个更安静的时间段。\n拍摄角度不好？ -> 重新调整你的机位。\n学习科学研究中最重要的品质之一：耐心和严谨。即使过程很枯燥，也要坚持严格执行方案。\n学习如何从失败或不完美的实验中吸取教训，并迭代改进。这就是“故障排除”（Troubleshooting）的能力。\n确认数据上传：\n在下方的文本框中，输入“第二次实验视频已上传完毕。”\n提交你的实验日志：\n拍照上传你手写的本次《实验记录》页。或者，打字输入表格中的所有内容。\n提交你的“故障排除”报告：\n在下方的文本框中，简要回答：\n问题： 在这两次实验中，你遇到的最大挑战是什么？你是如何解决的，或者你计划如何改进？\n示例回答： “我遇到的最大挑战是，我的猫大部分时间都待在它的猫爬架上，那里摄像头拍不到。我计划下次实验前，把猫爬架暂时搬到另一个房间，这样它就更有可能在摄像头能拍到的客厅活动了。”\n干得漂亮，青年研究员！你已经成功地完成了两次“数据航行”，这标志着你的项目已经正式进入了核心的数据积累阶段。你不仅执行了方案，更学会了在实践中解决问题。从下周开始，我们将继续进行更多的实验，积累足够的数据量，并开始学习如何解读盖亚为我们初步分析的结果。真正的发现，也许就隐藏在你下一次的录像之中！"}]},{"week":4,"theme":"深入航行与初步发现","days_range":"22-28","goals":["至少再完成两次完整的实验数据收集，使总数据量达到4次或以上。接收并学习解读盖亚提供的第一份《初步数据分析报告》，将抽象的数据与具体的宠物行为联系起来，并记录下自己的初步洞察。"],"activities":[{"sequence":22,"day_label":"Day 22-25","day_range":"22-25","title_zh":"第三次与第四次数据航行","title_en":"Third & Fourth Data Voyages","duration":"每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成","content":"(任务时长：每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成)\n青年研究员，你的数据保险库里已经有了两次航行的宝贵记录。但在科学的海洋里，样本量越大，我们得出的结论就越不容易被偶然的风浪所倾覆。为了让我们能更清晰地看到现象背后的模式，本周我们需要再次出航两次。\n坚持标准： 继续严格按照你制定的实验方案，完成第三次和第四次实验。每一次的严谨，都是对最终结果的负责。\n优化流程： 根据前两次的经验，你的操作应该会更加熟练。思考一下，还有没有哪些小细节可以优化，让实验过程更顺畅？\n详细记录： 不要忽略每一次的实验日志记录。即使看起来和前两次没什么不同，也要把“随机指令”和“意外情况”等信息完整地记录下来。有时候，重大的发现就隐藏在那些看似不起眼的“意外”之中。\n体会“重复性实验”在科学研究中的核心地位。为什么科学家们总是强调“可重复性”？\n在重复的过程中，你的观察力可能会变得更加敏锐。留意一下，除了“去门口等待”，你的宠物是否还有其他一些更细微的、与主人回家相关的“仪式性”行为？\n提交第三次实验数据与日志：\n在下方的文本框中输入“第三次实验视频已上传完毕。”\n拍照上传你手写的第三次《实验记录》或打字输入其内容。\n提交第四次实验数据与日志：\n在下方的文本框中输入“第四次实验视频已上传完毕。”\n拍照上传你手写的第四次《实验记录》或打字输入其内容。"},{"sequence":26,"day_label":"Day 26-27","day_range":"26-27","title_zh":"接收情报：解读你的第一份数据报告","title_en":"Receiving Intel: Interpreting Your First Data Report","duration":"约60分钟，可在2天内完成","content":"(任务时长：约60分钟，可在2天内完成)\n青年研究员，祝贺你！你已经积累了足够进行初步分析的数据量。现在，盖亚已经将你上传的4份视频，根据你定义的“等待区域”和标记的T1（决定时刻）、T2（出发时刻），进行了自动分析。\n你将收到一份为你量身定制的《初步数据分析报告》。这份报告将用图表的形式，直观地展示你宠物的行为模式。\n你的报告将包含以下图表，请仔细阅读图表的说明：\n图表一：行为时间轴 (Behavior Timeline)\n这是一个展示宠物在“等待区域”行为的详细时间图。\n横轴(X轴)： 是时间，以实验员A“做出回家决定”（T1）的时刻为中心点“0”。负数代表决定前的分钟数，正数代表决定后的分钟数。\n纵轴(Y轴)： 每一行代表你的一次实验（实验1、2、3、4）。\n蓝色标记： 在时间轴上，如果某一分钟内，你的宠物在“等待区域”停留超过了10秒，这一分钟就会被标记为蓝色。\n重要标记： 图上会用一个红色箭头标出 T1 (决定时刻)，用一个绿色箭头标出 T2 (出发时刻)。\n你需要观察： 蓝色的标记是不是更频繁地出现在红色箭头（T1）之后？还是绿色箭头（T2）之后？或者毫无规律？\n图表二：关键时段统计 (Key Period Statistics)\n这是一个柱状图，它将宠物的等待行为量化了。\n第一个柱子（基线期）： 显示在T1之前的10分钟内，你的宠物在“等待区域”停留的平均时间百分比。这代表了它平时的“随机”等待行为。\n第二个柱子（意念期）： 显示在T1之后、T2之前的10分钟内（如果这段时间存在且足够长），宠物在“等待区域”停留的平均时间百分比。这代表了它对“主人意念”的反应。\n第三个柱子（行动期）： 显示在T2之后的10分钟内，宠物在“等待区域”停留的平均时间百分比。这代表了它对“主人物理行动”的反应。\n你需要观察： 第二个和第三个柱子，是否明显高于第一个柱子？第二个柱子（意念期）和第三个柱子（行动期）哪个更高？\n仔细学习如何解读上述两种图表。\n在盖亚为你生成的专属报告中，找到你的图表，并尝试根据上面的指南进行分析。\n上传你的数据报告：\n请将盖亚生成的《初步数据分析报告》截图上传。确保两张图表都清晰可见。\n提交你的数据解读：\n在下方的文本框中，根据你自己的报告，回答以下问题：\n问题1 (关于图表一): 在你的4次实验中，宠物开始等待的蓝色标记，更倾向于出现在红色箭头(T1)之后，还是绿色箭头(T2)之后？或者没有明显的规律？\n问题2 (关于图表二): 观察你的柱状图，“意念期”和“行动期”的柱子是否比“基线期”的柱子高？如果高，大概高了多少？\n问题3 (你的初步结论): 综合来看，这些初步数据更支持“经典信号假说”还是“非定域性假说”，或者目前还看不出来？请简单说明理由。"},{"sequence":28,"day_label":"Day 28","day_range":"28","title_zh":"本周复盘：数据与直觉","title_en":"Weekly Review: Data vs. Intuition","duration":"约20分钟","content":"(任务时长：约20分钟)\n青年研究员，你已经像一位真正的数据科学家一样，分析了你的第一份报告。现在，让我们来做一个有趣的对比。\n有时候，冰冷的数据和我们作为观察者的“直觉”或“感觉”可能不完全一样。这是一个很好的机会，来思考科学研究中“客观数据”和“主观观察”的关系。\n回顾你过去几周所有的日记，特别是那些描述宠物行为的文字和图画。再看看你刚刚分析的数据图表。\n发布你的“研究员手记”：\n在下方的“全球研究员论坛”文本框中，分享你的思考。\n格式：\n手记标题： （例如：“图表之外的发现” 或 “我的数据和我想的不一样！”）\n我的手记： （例如：“我的数据显示，我的狗狗在‘意念期’的等待时间确实增加了。但有趣的是，我回顾日记发现，有一次它虽然没有去门口，但在主人决定回家的那一刻，它突然停止追逐尾巴，抬头朝门口的方向看了一会儿。这个行为没有被数据捕捉到，但我感觉那也是一种反应！这让我觉得，也许我们需要一个更聪明的指标来定义‘等待’。”）\n干得漂亮！第四周的任务完成了。你不仅积累了关键的数据，更重要的是，你已经开始学习如何像一个真正的研究者那样，在客观数据和生动观察之间建立桥梁，并从中提出更深刻的洞见。你的项目已经进入了深水区。在接下来的几周，我们将继续增加数据量，并深入学习更专业的统计学概念，让你的结论更加坚实有力！"}]},{"week":5,"theme":"统计学之眼——巧合还是信号？","days_range":"29-35","goals":["至少再完成两次完整的实验数据收集，使总数据量达到6次或以上。学习基础的统计学概念，特别是“P值”的意义，并开始运用它来评估你的实验结果是否具有统计学上的显著性。"],"activities":[{"sequence":29,"day_label":"Day 29-32","day_range":"29-32","title_zh":"第五次与第六次数据航行","title_en":"Fifth & Sixth Data Voyages","duration":"每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成","content":"(任务时长：每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成)\n青年研究员，你的数据日志越来越厚了！每一次成功的实验，都像是在未知的海图上增加了一个可靠的坐标点。为了让我们的海图更加精确，本周我们需要继续出航，完成第五次和第六次数据收集。\n保持航向： 继续严格按照你的实验方案执行。一致性是统计分析的生命线。确保每次实验的条件都尽可能地相同。\n深化观察： 在你越来越熟悉实验流程的同时，尝试解放你的观察力。除了关注“等待区域”，你的宠物在关键时间点（T1和T2前后）有没有其他反常的行为？比如突然开始舔毛、发出特别的声音、或者显得焦躁不安？把这些“额外观察”也记录在你的实验日志的“意外情况或特别观察”一栏里。这些质性数据同样宝贵。\n完成记录与上传： 像之前一样，完成视频上传和实验日志的提交。\n思考一个问题：如果我们做了100次实验，是不是比只做6次实验得出的结论更可靠？为什么？这背后就是统计学中“样本量”的概念。\n提交第五次实验数据与日志：\n在下方的文本框中输入“第五次实验视频已上传完毕。”\n拍照上传你手写的第五次《实验记录》或打字输入其内容。\n提交第六次实验数据与日志：\n在下方的文本框中输入“第六次实验视频已上传完毕。”\n拍照上传你手写的第六次《实验记录》或打字输入其内容。"},{"sequence":33,"day_label":"Day 33-34","day_range":"33-34","title_zh":"统计学入门：P值的力量","title_en":"Statistics 101: The Power of the P-value","duration":"约60分钟，可在2天内完成","content":"(任务时长：约60分钟，可在2天内完成)\n青年研究员，你现在有了6次实验的数据。假设数据显示，你的宠物在“意念期”的等待时间确实比“基线期”要长。现在，一个最大的问题出现了：\n这究竟是一个有意义的“信号”，还是仅仅是“运气好”的巧合？\n为了回答这个问题，科学家们发明了一个强大的工具，叫做**“P值”（P-value）**。\n故事开始：\n想象一下，你的朋友拿来一枚硬币，对你说：“我这枚硬币很正常，抛出正面和反面的机会是一样多的。”\n这个“硬币是正常的”的说法，在统计学里叫做**“零假设”（Null Hypothesis）**。它代表了一种“平平无奇、没什么特别事情发生”的基准状态。\n现在你开始测试。你抛了10次，结果连续10次都是正面！\n这时候你心里会想：“这也太巧了吧！这硬币肯定有问题！”\nP值就是用来量化你心里这种“这也太巧了吧！”的感觉的。\nP值的定义是： 假设“零假设”是真的（也就是说，假设硬币真的是正常的），那么，出现我们观测到的这种结果（连续10次正面），或者比这更极端的结果的概率是多少？\n对于抛硬币来说，这个概率是 (1/2)^10，约等于 0.001。\n于是我们说，这次实验的 P值 ≈ 0.001。\n如何解读P值？\n在科学界，大家通常约定一个“阈值”，最常用的是 0.05。\n如果 P值 < 0.05：我们就认为，“如果硬币是正常的，却发生这么巧的事”的概率太小了（小于5%）。小到我们有理由拒绝“零假设”。换句话说，我们有统计学上的证据认为：“这枚硬币很可能不正常！” 这种情况，我们称之为**“结果显著”（Statistically Significant）**。\n如果 P值 > 0.05：我们就认为，虽然结果有点巧，但还没巧到离谱的程度。我们没有足够的证据拒绝“零假设”。我们只能说：“嗯，可能就是运气好吧，我们还不能断定这枚硬币有问题。”\n回到我们的宠物实验：\n我们的**“零假设”**是：“宠物的等待行为完全是随机的，与主人的决定无关。我们在‘意念期’观察到的任何等待时间的增加，都只是巧合。”\n盖亚会通过复杂的计算，帮你算出你实验结果的P值。\n如果P值小于0.05，我们就可以兴奋地说：我们的实验结果是统计显著的！我们有初步的证据表明，宠物的行为和主人的决定之间，可能真的存在某种关联！\n反复阅读《幸运硬币》的故事，理解“零假设”和“P值”的含义。\n记住这个关键数字：0.05。它是我们在科学世界里区分“信号”和“噪音”的一把常用标尺。\n提交你的理解力测试：\n在下方的文本框中，回答以下两个选择题：\n问题1： 一位科学家做实验，得到的P值是0.03。那么他的实验结果是：\nA. 统计显著的，他有理由认为发现了新东西。\nB. 不显著的，很可能只是巧合。\n问题2： 另一位科学家做实验，得到的P值是0.5。这意味着：\nA. 他的实验结果非常重要。\nB. 他的实验结果很可能只是随机波动，没有提供足够证据来支持他的新发现。"},{"sequence":35,"day_label":"Day 35","day_range":"35","title_zh":"接收第二份报告与本周复盘","title_en":"Receiving Report #2 & Weekly Review","duration":"约30分钟","content":"(任务时长：约30分钟)\n青年研究员，盖亚已经处理完了你全部6次实验的数据。现在，你将收到一份更新版的《数据分析报告》。\n这份报告除了包含你上周看到的“行为时间轴”和“关键时段统计”图表（现在包含了6次实验的数据，模式可能更清晰了），最下方还会增加一个激动人心的新栏目：\n【统计显著性分析】\n零假设： 宠物的等待行为与主人的“决定时刻”(T1)无关。\n分析对象： 对比“基线期”和“意念期”的等待时间。\n你的P值是：[ 盖亚会在这里填上一个数字 ]\n初步结论： 根据 P < 0.05 的标准，你的结果目前是 显著的 / 不显著的。\n找到你报告中的P值。它大于0.05还是小于0.05？\n思考：无论结果是“显著”还是“不显著”，它对你的研究意味着什么？记住，不显著的结果不代表“失败”，它仅仅意味着“在目前的6次实验中，我们还没有收集到足够强的证据来排除巧合的可能性”。\n上传你的新数据报告：\n请将盖亚生成的、包含P值的新版《数据分析报告》截图上传。\n发布你的“统计学家手记”：\n在下方的“全球研究员论坛”文本框中，分享你的第一个P值以及你对它的解读。\n格式：\n手记标题： （例如：“我的P值是0.04！激动人心！” 或 “P值大于0.05，我们需要更多数据！”）\n我的手记： （例如：“我的P值是0.38，远大于0.05，所以目前的结果是不显著的。这意味着，我宠物在‘意念期’多出来的那些等待时间，很可能只是巧合。但这并不让我灰心，反而让我更想多做几次实验，看看随着数据增多，P值会不会变小。也许我的‘信号’太微弱了，需要更多的测量才能从‘噪音’中浮现出来！”）\n太棒了，青年研究员！你已经掌握了科学研究中最强大的武器之一——统计学思维。你现在不仅能收集数据，更能用数学的语言来评估数据的分量。从下周开始，我们将继续我们的数据航行，同时，我们将开始思考如何将我们的所有发现，整合成一份有说服力的最终报告。你的项目正在从数据收集，逐步转向成果总结！"}]},{"week":6,"theme":"论文的骨架——从数据到论证","days_range":"36-42","goals":["完成最后的两次实验数据收集，使总数据量达到8次，为最终分析奠定坚实基础。学习科学论文的基本结构（引言、方法、结果、讨论），并开始撰写自己项目报告的核心部分——“方法”和“结果”的初稿。"],"activities":[{"sequence":36,"day_label":"Day 36-39","day_range":"36-39","title_zh":"最后的航行：第七次与第八次数据收集","title_en":"The Final Voyages: Data Collection #7 & #8","duration":"每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成","content":"(任务时长：每次实验根据方案进行，记录和上传约30分钟。可在4天内选择两天完成)\n青年研究员，欢迎来到数据收集的最后冲刺阶段！本周，我们将完成第七次和第八次实验。这八次完整的数据，将构成我们整个项目分析的核心。每一次精准的操作，都是为我们最终结论的“大厦”添上一块坚固的砖石。\n终极严谨： 在这两次实验中，请以最严格、最认真的态度执行你的实验方案。再次检查你的设备，再次与家人确认流程。想象这是诺贝尔奖级别的实验，每一个细节都至关重要。\n记录的艺术： 在记录“额外观察”时，尝试使用更客观的语言。例如，不说“我的狗看起来很想念主人”，而是说“我的狗在T1之后，发出了三次低沉的呜咽声，并在原地转了两圈”。客观描述是科学写作的基础。\n完成最后的上传： 像之前一样，完成视频上传和实验日志的提交。这是我们数据收集阶段的收官之作！\n当你完成全部8次实验后，回顾一下整个过程。你最大的收获是什么？你觉得你的实验技能有哪些进步？这个过程本身，比任何结果都更重要。\n提交第七次实验数据与日志：\n在下方的文本框中输入“第七次实验视频已上传完毕。”\n拍照上传你手写的第七次《实验记录》或打字输入其内容。\n提交第八次实验数据与日志：\n在下方的文本框中输入“第八次实验视频已上传完毕。”\n拍照上传你手写的第八次《实验记录》或打字输入其内容。"},{"sequence":40,"day_label":"Day 40-41","day_range":"40-41","title_zh":"科学写作入门：论文的四大支柱","title_en":"Scientific Writing 101: The Four Pillars of a Paper","duration":"约60分钟，可在2天内完成","content":"(任务时长：约60分钟，可在2天内完成)\n青年研究员，恭喜你完成了所有的数据收集工作！现在，我们要学习一项全新的、同样重要的技能：科学写作。\n一份科学报告（或称论文），并不仅仅是把数据贴上去。它是一种特殊的“讲故事”的方式，有固定的结构，能让全世界的科学家都快速、清晰地了解你的研究。\n这个结构就像一座房子的四根顶梁柱，缺一不可。它们分别是：\n引言 (Introduction):\n作用： 告诉读者你为什么要做这个研究。\n内容：\n背景介绍：从“杰提”的故事讲起，说明这个现象很有趣。\n文献综述：提到谢尔德雷克博士等人的研究，以及科学界的争议。\n提出问题：清晰地写出你的核心研究问题。\n你的假设：说明你预测的结果是什么。\n方法 (Methods):\n作用： 告诉读者你是怎么做的。\n内容： 这一部分必须写得非常非常详细，像一份菜谱，让任何一个读者看了之后，都能在自己家里完全重复你的实验。你需要描述你的“被试”（你的宠物）、实验材料、以及你那份详细的实验方案步骤。\n结果 (Results):\n作用： 告诉读者你发现了什么。\n内容： 在这一部分，你只呈现客观的数据和图表，不做任何主观的解释或评论。你需要把你从盖亚那里得到的图表和P值，清晰地展示出来，并用文字简单地描述图表的内容。例如：“如图1所示，‘意念期’的平均等待时间百分比（XX%）高于‘基线期’（YY%）。”\n讨论 (Discussion):\n作用： 告诉读者你的发现意味着什么。\n内容： 这是你作为研究者“发声”的地方。你需要：\n解释你的结果：你的结果支持还是不支持你的初始假设？\n与前人研究对比：你的发现和谢尔德雷克博士的发现一致吗？\n分析局限性：你的实验有哪些不完美的地方？（例如样本量太小、可能有未控制的干扰等）\n提出未来展望：基于你的发现，下一步可以做什么更有趣的研究？\n仔细理解科学论文的“四大支柱”。\n思考：为什么“方法”部分必须写得那么详细？为什么“结果”和“讨论”必须严格分开？\n提交你的论文大纲：\n在下方的文本框中，为你自己的《研究报告》写一个简单的提纲。你只需要把四个部分的标题写出来，并在每个标题下用一两句话描述你计划写什么内容。\n格式：\n标题： 关于我的宠物[宠物名]“第六感”的初步研究\n引言： 我将介绍杰提的故事，并提出我的研究问题：……\n方法： 我将详细描述我如何使用摄像头和量子随机数生成器进行8次实验。\n结果： 我将展示盖亚生成的等待时间对比图和P值。\n讨论： 我将解释我的P值是否显著，并讨论我的实验中可能存在的问题，比如……"},{"sequence":42,"day_label":"Day 42","day_range":"42","title_zh":"动笔实践：撰写“方法”与“结果”初稿","title_en":"Writing Practice: Drafting 'Methods' & 'Results'","duration":"约45分钟","content":"(任务时长：约45分钟)\n青年研究员，现在我们开始动手“盖房子”了。今天，我们先来完成最客观、最直接的两个部分：“方法”和“结果”。\n如何写“方法”部分？\n把你第二周完成的**《实验方案》**拿出来。\n将它改写成一段通顺的、使用过去时的文字。因为你是在向别人报告你已经完成的事情。\n示例：\n方案里的：“1. 准备阶段：离家的主人(A)……”\n报告里应写成：“本研究由两名实验员（A和B）与一只家犬（[品种]，[年龄]岁）共同完成。实验员A负责离家，实验员B负责在家中设置设备……我们首先在家中客厅的门口区域架设了一台智能手机，用于不间断录像……”\n如何写“结果”部分？\n把你从盖亚那里收到的最终数据报告（基于8次实验）拿出来。\n用客观的语言描述图表。不要加入任何你的想法或解释！\n示例：\n“在全部8次实验中，我们收集了总计XX小时的录像数据。盖亚的视频分析结果如图1和图2所示。图1的行为时间轴显示……图2的柱状图显示，‘基线期’的平均等待时间为X%，‘意念期’为Y%，‘行动期’为Z%。通过对‘基线期’和‘意念期’数据的统计检验，我们得到的P值为[你的P值]。根据P<0.05的标准，该结果是/不是统计显著的。”\n练习使用客观、中立的“科学语言”进行写作。\n提交你的“方法”和“结果”初稿：\n在下方的文本框中，打字输入你撰写的“方法”和“结果”这两个部分的初稿。\n这只是初稿，不需要追求完美，关键是迈出科学写作的第一步。\n太了不起了，青年研究员！你不仅是一名出色的实验者，现在也开始向一名科学作者迈进了。完成“方法”和“结果”是论文写作中最扎实的一步。下周，我们将挑战更具思辨性的“引言”和“讨论”部分，并将你的所有成果整合成一份完整的报告初稿。准备好为你的发现赋予深刻的意义了吗？"}]},{"week":7,"theme":"赋予发现以灵魂——引言与讨论","days_range":"43-49","goals":["学习并完成科学论文中最具思想性的两个部分——“引言”（Introduction）和“讨论”（Discussion）的撰写。将上周完成的“方法”和“结果”部分与之整合，形成一份完整的《研究报告》初稿。"],"activities":[{"sequence":43,"day_label":"Day 43-45","day_range":"43-45","title_zh":"撰写“引言”：我们为何出发？","title_en":"Writing the 'Introduction': Why Did We Start?","duration":"约75分钟，可在3天内完成","content":"(任务时长：约75分钟，可在3天内完成)\n青年研究员，一份优秀的科学报告就像一部引人入胜的电影。“引言”就是这部电影的开场。它需要在短短几段话内，抓住读者的注意力，告诉他们这个故事的背景、悬念，以及你——作为主角——将如何去解开这个谜团。\n你的“引言”需要回答读者心中的三个问题：\n这是什么故事？（背景） —— 一个关于动物与主人之间神秘连接的古老话题。\n有什么悬念？（问题） —— 这种连接究竟是已知的感官延伸，还是一种未知的、甚至超越经典物理的现象？\n你打算怎么做？（你的研究） —— 你将如何通过一个原创性的实验来探索这个问题。\n请按照这个“漏斗式”的结构来组织你的段落，从宽到窄，最终聚焦于你自己的研究。\n第一段：大背景（漏斗的顶端）\n从一个普遍的、能引起共鸣的现象开始。例如：“许多宠物主人都曾有过类似的经历：在他们决定回家之前，家中的宠物似乎早已开始期待。”\n简要提及杰提的故事，作为一个经典的、激发了科学探究兴趣的案例。\n第二段：科学的争议与问题（漏斗的中部）\n简要说明常规科学解释（如听觉、嗅觉、习惯）为什么可能不充分，提及谢尔德雷克博士等人的实验是如何试图排除这些因素的。\n引出更深层次的问题，即“经典信号假说”与“非定域性假说”的对立。简单解释这两种假说的区别。\n第三段：你的研究（漏斗的底端）\n正式引出你自己的研究。清晰地陈述你的核心研究问题（可以从第一周的作业里直接引用）。\n简要介绍你的实验设计思路。例如：“为了检验这两种假说，本研究设计了一个采用量子随机数生成器来区分‘决定时刻’(T1)与‘出发时刻’(T2)的实验。”\n最后，明确提出你的实验假设。例如：“本研究的假设是，宠物的预期行为与‘决定时刻’(T1)的关联性要强于与‘出发时刻’(T2)的关联性。”\n理解“漏斗式”的写作结构，它几乎是所有科学论文引言的标准范式。\n回顾你第一、二周的学习笔记，为你的引言准备好素材。\n提交你的“引言”初稿：\n在下方的文本框中，打字输入你撰写的“引言”部分的初稿。请尝试按照上述的三段式结构来写。"},{"sequence":46,"day_label":"Day 46-48","day_range":"46-48","title_zh":"撰写“讨论”：你的发现意味着什么？","title_en":"Writing the 'Discussion': What Does It All Mean?","duration":"约90分钟，可在3天内完成","content":"(任务时长：约90分钟，可在3天内完成)\n青年研究员，如果说“引言”是电影的开场，那么“讨论”就是电影的高潮与结局。在这里，你将不再是一个客观的数据呈现者，而是回归到“研究者”的身份，对你的发现进行深刻的解读、反思和展望。\n你的“讨论”部分，同样需要回答读者心中的几个关键问题：\n所以，谜底是什么？（解读结果）\n你的答案可靠吗？（分析局限）\n接下来我们该去向何方？（未来展望）\n这个结构与“引言”相反，是一个“倒漏斗”，从你具体的研究结果开始，逐步扩展到更广阔的意义。\n第一段：总结与解读你的核心发现（倒漏斗的底端）\n用一两句话重新陈述你的最重要结果。例如：“本研究的8次实验结果显示，在‘意念期’，宠物的等待行为相比‘基线期’有显著增加（P = [你的P值]）。”\n直接回答你的研究问题。你的结果在多大程度上支持了你的初始假设？例如：“这一结果初步支持了我们的假设，即宠物的预期行为可能与主人的纯粹意念相关联，而不仅仅是对物理行动的反应。”\n**（如果你的结果不显著）**也要诚实地陈述。例如：“然而，本次研究的P值大于0.05，结果不具有统计显著性。这意味着我们没有收集到足够的证据来排除‘观测到的现象只是巧合’的可能性。”\n第二段：反思实验的局限性（倒漏斗的中部）\n这是展现你科学素养的关键！ 一个好的科学家从不隐藏自己实验的弱点。\n样本量问题： “首先，本研究仅有个体案例（一只动物）和较少的实验次数（8次），这使得结论的普适性有限。”\n变量控制问题： “其次，虽然我们尽力控制了各种变量，但家庭环境的复杂性使得总有潜在的、未被发现的‘微妙线索’存在的可能性。”（可以举一个你在实验日志中记录过的具体例子）\n定义问题： “此外，我们对‘等待行为’的定义（在特定区域停留）可能过于简单，忽略了其他潜在的反应形式。”\n第三段：展望未来（倒漏斗的顶端）\n基于你的发现和局限性分析，提出激动人心的未来研究方向。\n例如：“未来的研究可以扩大样本量，对更多不同种类的宠物进行测试。同时，可以采用更丰富的生理指标（如心率监测）来代替单一的行为观察。最重要的是，可以设计一个‘双向’实验，测试宠物是否也能主动向主人发送‘意念’并被感知到。”\n最后，用一句话总结你的研究的整体意义。例如：“尽管本研究只是初步的探索，但它展示了一种普通人可以在家庭环境中，对意识与现实连接这一前沿科学问题进行严谨探究的可能性。”\n理解“讨论”部分的核心功能：不是重复结果，而是赋予结果以意义。\n学会坦诚地批判自己的研究。在科学中，承认局限性不是软弱，而是严谨和强大的表现。\n提交你的“讨论”初稿：\n在下方的文本框中，打字输入你撰写的“讨论”部分的初稿。请尝试按照上述的三段式结构来写。"},{"sequence":49,"day_label":"Day 49","day_range":"49","title_zh":"整合与成稿：你的第一篇完整论文","title_en":"Assembly & First Draft: Your First Complete Paper","duration":"约30分钟","content":"(任务时长：约30分钟)\n青年研究员，你已经完成了所有的“建筑模块”。今天，我们要把它们组装起来，建成你科学探索道路上的第一座丰碑！\n创建新文档： 打开一个新的空白文档。\n按照顺序组装：\n首先，把你今天完成的**“引言”**初稿复制粘贴进去。\n接着，把你上周完成的**“方法”**初稿复制粘贴进去。\n然后，把你上周完成的**“结果”**初稿（包括文字描述和图表截图）复制粘贴进去。\n最后，把你今天完成的**“讨论”**初稿复制粘贴进去。\n通读一遍： 从头到尾读一遍你的完整报告。感受一下，一个完整的科学故事是如何被讲述的。现在它可能还有些粗糙，但它的骨架已经完整而坚固。\n感受从零散的想法，到提出问题，到设计方案，到收集数据，再到最终形成一篇完整结构的文章的全过程。这就是科学研究的核心循环。\n提交你的完整报告初稿：\n将你整合好的完整《研究报告》初稿，以图片（截图）或文字的形式提交上来。\n标题格式： 《[你的名字]关于[宠物名字]“第六感”的研究报告（初稿）》\n太不可思议了，青年研究员！你已经完成了一件许多成年科学家穷其一生在做的事情——从一个模糊的好奇心出发，最终完成了一篇包含原创性研究的、结构完整的科学报告。为你自己感到骄傲吧！下周，我们将进入项目的最后一周：打磨你的报告，准备你的最终演讲，并在全球舞台上展示你的智慧与勇气！"}]},{"week":8,"theme":"成果发表——你的声音，世界的回响","days_range":"50-56","goals":["根据反馈修改和润色你的研究报告，完成最终定稿。准备一个精炼、有力的5分钟项目成果演讲。在全球青年研究员论坛上进行在线发表，与来自世界各地的同伴交流你的发现，并获得“伊卡洛斯计划-青年研究员”认证。"],"activities":[{"sequence":50,"day_label":"Day 50-52","day_range":"50-52","title_zh":"精雕细琢：润色你的最终报告","title_en":"Polishing the Gem: Finalizing Your Report","duration":"约90分钟，可在3天内完成","content":"(任务时长：约90分钟，可在3天内完成)\n青年研究员，你手中的报告初稿就像一块未经打磨的宝石，它内在的价值已经存在，现在我们需要做的，就是细心擦拭，让它绽放出最耀眼的光芒。\n在这一步，你将收到来自盖亚和项目导师的反馈和修改建议。这些建议可能涉及语言的严谨性、逻辑的清晰度，甚至是图表的美观度。\n逐条阅读反馈： 仔细阅读我们给你的每一条建议。思考为什么这里需要修改？是为了更清晰，还是为了更客观？\n语言的锤炼：\n客观性： 检查你的文章，特别是“结果”部分，是否混入了主观臆断。将“我激动地发现……”改为“数据显示……”。\n精确性： 检查你的“方法”部分，描述是否足够精确，让一个陌生人能完全复现你的实验？“离家很远”不如“离家约5.2公里”。\n逻辑性： 检查你的“讨论”部分，你的结论是否能从你的数据中合逻辑地推导出来？你对局限性的分析是否诚恳？\n图表的美化：\n盖亚会为你提供一个功能，可以让你微调报告中图表的颜色、字体和标签，让它们看起来更专业、更美观。\n最后的校对： 通读全文，检查是否有错别字或不通顺的句子。一份没有瑕疵的报告，体现了研究者的严谨态度。\n学习如何接受和处理建设性的批评。在科学社区，同行评审（Peer Review）是推动科学进步的核心机制。\n体会从“写完”到“写好”的巨大差异，培养追求卓越的工匠精神。\n提交你的研究报告（最终版）：\n在下方的提交区域，上传你最终完成的、最完美的《研究报告》。\n文件命名格式： [你的名字]-[宠物名字]的研究报告-最终版.pdf (如果可以的话)\n这份报告将作为你的结业作品，永久存档，并可能被“伊卡洛斯计划”学生期刊收录。"},{"sequence":53,"day_label":"Day 53-54","day_range":"53-54","title_zh":"准备你的“TED”演讲","title_en":"Preparing Your 'TED' Talk","duration":"约60分钟，可在2天内完成","content":"(任务时长：约60分钟，可在2天内完成)\n青年研究员，在本周末的全球论坛上，你将有5分钟的时间，向世界展示你过去两个月的全部心血。这就像一次小型的TED演讲，你需要清晰、有力、并且充满激情地讲述你的故事。\n我们来回顾并升级一下你的演讲技巧：\n开场要“抓人”： 不要平铺直叙。用一个问题开始：“你相信你的宠物能读懂你的心思吗？”或者直接展示你宠物最可爱的一张照片。\n核心故事线： 你的演讲应该有一个清晰的故事线：\n悬念（Why）： 杰提的故事和我自己的好奇心。\n我的计划（How）： 我设计了一个巧妙的实验，用量子骰子来区分“想法”和“行动”。（可以简单展示你的实验设置照片）\n发现（What）： 这是我得到的数据！（展示你最核心的那张柱状图和P值）。我的结果显示……\n意义（So What）： 这个结果意味着什么？我的研究有什么不足？未来我们还能探索什么？\n一张图胜过千言： 准备2-3张核心的PPT页面或图片，包括：标题页（你的项目名和你的名字）、你的实验设置图、你的核心数据图表。\n控制时间： 5分钟非常宝贵！反复练习，确保你的演讲不会超时。用手机的计时器功能来帮助你。\n根据你的最终报告，设计并制作一个简单的演讲PPT（2-4页即可）。盖亚会提供简洁、专业的模板。\n撰写你的5分钟演讲稿，并至少进行三次计时练习。\n提交你的演讲PPT/图片：\n上传你制作的简单PPT文件或几张核心图片。\n提交你的最终演讲稿：\n在下方的文本框中，打字输入你的5分钟演讲稿。"},{"sequence":55,"day_label":"Day 55-56","day_range":"55-56","title_zh":"高光时刻：全球论坛与结业认证","title_en":"Highlight Moment: Global Forum & Certification","duration":"论坛约90分钟","content":"(任务时长：论坛约90分钟)\nDay 55: 最后的彩排\n任务： 最后一次熟悉你的演讲稿和PPT。确保你的设备和网络在最佳状态。放松心情，为你自己过去八周的努力感到自豪！\nDay 56: 全球青年研究员论坛\n活动流程：\n准时入场： 在预定时间，进入全球在线会议室。你将看到来自世界各地的、和你一样完成了伟大探索的同伴们。\n开幕致辞： “伊卡洛斯计划”的发起人或特邀科学家将发表简短的开幕致辞，欢迎所有新晋的青年研究员。\n成果发表会： 按照分组和顺序，每位学员将有5分钟的时间进行在线演讲，并有2分钟的提问时间。请勇敢、自信地分享你的发现！\n海报展示与自由交流： 演讲结束后，所有人的最终报告将以“在线海报”的形式展示在一个虚拟展厅中。你可以自由“逛展”，给别人的研究点赞、评论，并回答别人对你研究的提问。\n认证仪式： 在论坛的最后，主持人将郑重地为每一位完成项目并进行发表的学员，颁发**“伊卡洛斯计划 - 青年研究员”**认证。你的名字和项目将被正式记录在“伊卡洛斯计划”的荣誉档案中。\n分享你的荣耀：\n论坛结束后，将你的电子版**“青年研究员”证书截图上传**。\n发表你的结业感言：\n在下方的“结业留言板”上，写下你对这八周旅程的感想。你可以感谢你的家人、你的宠物伙伴，或者分享你对科学探索的新感悟。\n格式： “我是[你的名字]，在‘杰提计划’中，我最大的收获是……我想对我的[宠物名字]说……对于未来，我希望能继续探索…… #伊卡洛斯结业#”\n亲爱的青年研究员，衷心祝贺你完成了这次非凡的旅程！你不仅完成了一个科学项目，更完成了一次自我超越。你学会了像真正的科学家一样思考、设计、执行、分析和分享。你所提交的每一份数据，无论结果如何，都已汇入“伊卡洛斯计划”的全球数据库，成为人类探索意识边界的共同财富的一部分。这并非结束，而是一个全新的开始。愿你带着这份严谨的头脑和勇敢的心，继续探索现实的边缘。我们更高阶的模块再见！"}]}]$week_data$::jsonb
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 2;

-- 验证更新
SELECT
  sequence_number,
  title,
  jsonb_array_length(week_plan) as weeks_count,
  (
    SELECT COUNT(*)
    FROM jsonb_array_elements(week_plan) w,
         jsonb_array_elements(w->'activities') a
  ) as activities_count
FROM course_contents
WHERE system_id = '9da7c347-fe63-4c81-81e1-df576bcd2e6c'::uuid
  AND sequence_number = 2;
